mapper.select:
SELECT q.*, u.real_name AS user_name, r.title AS resource_title, (SELECT COUNT(*) FROM qa_reply qr WHERE qr.question_id = q.id) AS reply_count FROM question_answer q LEFT JOIN sys_user u ON q.user_id = u.id LEFT JOIN teaching_resource r ON q.resource_id = r.id
AND q.title LIKE CONCAT('%', #{title}, '%')
AND q.status = #{status}
AND q.user_id = #{userId}
ORDER BY q.create_time DESC
